using UnityEngine;

/// <summary>
/// Marca um inimigo/NPC (ou qualquer GameObject com Rigidbody2D que não seja o
/// player) como "afectado pelo vento" (Tarefa #6 — WindZone).
///
/// O player é sempre afectado pelo vento (ver PlayerMotor2D.ApplyWind).
/// Objectos soltos com <see cref="Carryable"/> (caixas, pedras, o ovo, etc.)
/// também são sempre afectados enquanto não estiverem a ser carregados — não
/// precisam deste componente.
///
/// Para tudo o resto (inimigos, NPCs, decorações com Rigidbody2D dinâmico),
/// adicionar este componente marca explicitamente que devem reagir ao vento.
/// O peso usado para calcular a força é resolvido por
/// GameWeightUtil.GetWindWeightOf (ObjectWeight > EnemyData.stats.weight >
/// Rigidbody2D.mass > 1).
/// </summary>
[DisallowMultipleComponent]
public class WindAffectable : MonoBehaviour
{
    [Tooltip("Liga/desliga o efeito do vento neste objecto sem remover o componente (ex.: inimigos pesados/ancorados que NÃO devem ser empurrados por vento).")]
    public bool affectedByWind = true;
}
